from functools import lru_cache


class Solution:
    def minDistance(self, houses, k):
        houses = sorted(houses)
        n = len(houses)

        def cost(l, r):
            best = None
            for p in range(houses[l], houses[r] + 1):
                s = sum(abs(x - p) for x in houses[l:r + 1])
                if best is None or s < best:
                    best = s
            return best

        @lru_cache(maxsize=None)
        def rec(i, b):
            if b == 0:
                return 0 if i == n else float('inf')
            if i == n:
                return float('inf')
            best = float('inf')
            for j in range(i + 1, n + 1):
                sub = rec(j, b - 1)
                if sub < float('inf'):
                    v = cost(i, j - 1) + sub
                    if v < best:
                        best = v
            return best

        result = rec(0, k)
        rec.cache_clear()
        return result

