class Solution:
    def minDistance(self, houses, k):
        houses = sorted(houses)
        n = len(houses)
        cost = [[0] * n for _ in range(n)]
        for i in range(n):
            for j in range(i, n):
                mid = (i + j) // 2
                m = houses[mid]
                s = sum(abs(houses[x] - m) for x in range(i, j + 1))
                cost[i][j] = s
        INF = float('inf')
        dp = [[INF] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0
        for i in range(1, n + 1):
            for b in range(1, k + 1):
                for j in range(i):
                    if dp[j][b - 1] < INF:
                        val = dp[j][b - 1] + cost[j][i - 1]
                        if val < dp[i][b]:
                            dp[i][b] = val
        return dp[n][k]

