var minDistance = function(houses, k) {
    houses = houses.slice().sort((a, b) => a - b);
    const n = houses.length;
    const cost = Array.from({ length: n }, () => new Array(n).fill(0));
    for (let i = 0; i < n; i++) {
        for (let j = i; j < n; j++) {
            const mid = (i + j) >> 1;
            const m = houses[mid];
            let s = 0;
            for (let x = i; x <= j; x++) s += Math.abs(houses[x] - m);
            cost[i][j] = s;
        }
    }
    const INF = Infinity;
    const dp = Array.from({ length: n + 1 }, () => new Array(k + 1).fill(INF));
    dp[0][0] = 0;
    for (let i = 1; i <= n; i++) {
        for (let b = 1; b <= k; b++) {
            for (let j = 0; j < i; j++) {
                if (dp[j][b - 1] < INF) {
                    const val = dp[j][b - 1] + cost[j][i - 1];
                    if (val < dp[i][b]) dp[i][b] = val;
                }
            }
        }
    }
    return dp[n][k];
};
